AsymQ2 (f(a, b))
   Public final class AsymQ2 {
      // `a` has length M; `b` is sorted ascending and has length N.
      // Your analyzi must be based on M and N.
      public static int f(int[] a, int[] b) {
          int m = a.length;
          int s = 0;
          for (int I = 0; I < m; i++) {
              int t = g(b, a[i]);
              if (t >= 0) s += t;
          }
          return s;
      }

      private static int g(int[] b, int x) {
          int l = 0; // Iterations
          int r = b.length - 1; // Total number of iterations
          while (l <= r) { // Parts A and B
              int mid = (l + r) / 2; // Part C loop
              if (b[mid] == x) return mid; // If x is present in array b, return its index
              else if (b[mid] < x) l = mid + 1; // If the comparison favors part B, move to the next iteration
              else r = mid - 1; // If it doesn't, go back to the previous iteration and decrease the loop index
          }
          return -1; // If no match is found (i.e., x was not in b), return -1 to signal an error
      }
   }

